// LESSON: Collections and Arrays Utilities - Reference Page 2.
// You will learn: Use Collections and Arrays helpers for sorting, search, and fill.
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collections;
import java.util.List;

class CollectionsArraysReference {
  public static void main(String[] args) {
    example1CollectionsUtilities();
    example2BinarySearchAndView();
    example3ArraysUtilities();
    example4ArraysAsList();
  }

  static void example1CollectionsUtilities() {
    List<String> names = new ArrayList<>(Arrays.asList("Bo", "Ada", "Cy", "Ada"));
    Collections.sort(names);
    Collections.reverse(names);
    int adaCount = Collections.frequency(names, "Ada");
    String minName = Collections.min(names);
    String maxName = Collections.max(names);
    Collections.swap(names, 0, 1);
    System.out.println(names + " " + adaCount + " " + minName + " " + maxName);
  }

  static void example2BinarySearchAndView() {
    List<Integer> scores = new ArrayList<>(Arrays.asList(30, 10, 20));
    Collections.sort(scores);
    int index = Collections.binarySearch(scores, 20);
    List<Integer> readOnlyView = Collections.unmodifiableList(scores);
    scores.add(40);
    System.out.println(index + " " + readOnlyView);
  }

  static void example3ArraysUtilities() {
    int[] values = {3, 1, 2};
    Arrays.sort(values);
    int found = Arrays.binarySearch(values, 2);
    int[] copy = Arrays.copyOf(values, 5);
    Arrays.fill(copy, 3, 5, 9);
    System.out.println(Arrays.toString(copy) + " index=" + found);
  }

  static void example4ArraysAsList() {
    String[] words = {"java", "map", "list"};
    List<String> fixed = Arrays.asList(words);
    fixed.set(1, "queue");
    boolean same = Arrays.equals(words, new String[] {"java", "queue", "list"});
    System.out.println(fixed + " " + same);
  }
}
